import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './LoginPage.css'; // Import file CSS

function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    // Xử lý logic đăng nhập ở đây (gọi API, lưu token, v.v.)
    localStorage.setItem('token', 'dummyToken'); // Ví dụ lưu token giả
    localStorage.setItem('role', 'user'); // Ví dụ lưu vai trò
    navigate('/dashboard');
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <h2 className="login-title">Đăng nhập</h2>
        <form onSubmit={handleLogin}>
          <div className="login-form-group">
            <label htmlFor="email" className="login-label">E-mail</label>
            <input
              type="email"
              id="email"
              className="login-input"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="login-form-group">
            <label htmlFor="password" className="login-label">Mật khẩu</label>
            <input
              type="password"
              id="password"
              className="login-input"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>
          <button type="submit" className="login-button">Đăng nhập</button>
        </form>
        <p className="login-link">Chưa có tài khoản? <a href="/register">Đăng ký</a></p>

        {/* THÊM THÔNG TIN PHẦN MỀM VÀO ĐÂY */}
        <div className="login-software-info" translate="no">
          Phiên bản 1.0.0 <br />
          &copy; 2025 Nguyen Van Phuc
		   &copy; 035.758.358
		   &copy; Phuc88.klvn@gmail
        </div>
      </div>
    </div>
  );
}

export default LoginPage;
